import{_ as r,o as t,c as n,j as e,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"木棍与农具","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/木棍与农具.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/木棍与农具.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/木棍与农具.md"};function d(_,a,l,i,c,b){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"木棍与农具",tabindex:"-1"},[p("木棍与农具 "),e("a",{class:"header-anchor",href:"#木棍与农具","aria-label":'Permalink to "木棍与农具"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002")])])],-1),s('<h1 id="木棍与农具-1" tabindex="-1">木棍与农具 <a class="header-anchor" href="#木棍与农具-1" aria-label="Permalink to &quot;木棍与农具&quot;">​</a></h1><p>一根木棍<br> 100<br> 武器伤害1B<br> 一根40公分长的木棍，木棍上已经有很多因为浸水、膨胀导致的开裂，并且覆盖了一些黑色的污垢，散发着酸臭的腐败味道，用来当投掷物可能都会觉得恶心。</p><p>破损的金属农具<br> 100<br> 一个破碎的农具，已经看不出来源自什么物品，已经有了一层厚实的锈蚀，轻轻一握就会掉落许多碎片。可以将农具和木棍进行组合，成为一把破旧的镰刀，拥有武器伤害1L，分类为镰刀，但是由于其破损较为严重，每次攻击后都需要进行一个rd10的自然骰，如果出数小于5则会立马崩坏成两段，但是可以通过一个整轮将其重新修补绑定在一起。</p><p>如果清除掉这些锈蚀，可以看到上面有一些划痕，像是写了什么文字，拥有学识上的语言专业2级或者神秘学5级可以看懂。<br> “当灯笼亮起的时候，当乌鸦嘶吼的时候，当外形暴露的时候，它来喽”</p><p>看懂这些文字之后，可以支付B+2000奖励点，将木棍和农具进行组合，如果在剧情世界，需要花费等同造物的时间来进行融合，如果在主神世界，则可以由主神来进行协助。<br> 巫骇草人：融合后的武器像是一把锈蚀的镰刀，上面还有一些诡异的文字不停流淌，持有者则会在拿起的时候和武器完全融合，外表也会变成一个稻草人的外观，从外表上可以大体分辨出其本身的样貌，但是身体已经变成了木棍做成的十字架、浑身裹满了稻草。这把镰刀拥有15点法术强度，并且攻击会转化为等额的恐惧点数，标准方式豁免。</p><p>黑暗之风：当草人处于模糊定位、无法定位、不被视野线观察中的任意一种条件时，它会伪装成一个稻草人，即使它不使用伪装，当它在每回合第一次进入战斗，或者攻击一个因异常状态、生存状态等原因，进入无助状态时，都会在周身60米的范围内召唤出一个黑色的恐惧领域，攻击会转化为乌鸦冲击目标，并不停在范围内的目标之间进行弹射（每个目标只会因此受到一次伤害，但是其可以作为弹射的中介），弹射上限为使用者的操控点数。</p><p>恐惧降临：被这个武器攻击的目标会逐渐丧失抵抗的勇气，即使心智如钢铁般坚韧也会逐渐出现裂痕，每次被此武器攻击，都会导致被攻击者降低1点意志豁免，持续一个场景，如果目标被【黑暗之风】作为弹射中介，也会触发此能力，由此能力带来的意志豁免降低最多4点。</p><p>群鸦风暴<br> 支付A+4000，解锁此能力，在判定时，此能力分类为技能。<br> 当触发黑暗之风时，攻击范围内的目标会因突如其来的攻击进入【惊惧】，持续一个场景，标准方式豁免，这是一个A级心灵来源的效果，但是影响范围会提升至400米。并且恐惧降临的效果上限会提升至8点。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
